/**
 * @name EL injection via constraint violation message - data flow
 * @description Traces taint from constraint annotation message attributes to EL evaluation in ElTermResolver
 * @kind path-problem
 * @problem.severity error
 * @id java/el-injection-message-interpolation-flow
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// We want to track how the message string gets to EL evaluation
// ElTermResolver.interpolate receives a message string and evaluates it as EL
module ElInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // The interpolate method in ElTermResolver takes a 'term' string
    exists(Method m, Parameter p |
      m.hasName("interpolate") and
      m.getDeclaringType().hasQualifiedName("org.hibernate.validator.internal.engine.messageinterpolation", "ElTermResolver") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink is EL createValueExpression call argument
    exists(MethodCall mc |
      mc.getMethod().hasName("createValueExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.el", "ExpressionFactory") and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module ElInjectionFlow = DataFlow::Global<ElInjectionConfig>;
import ElInjectionFlow::PathGraph

from ElInjectionFlow::PathNode source, ElInjectionFlow::PathNode sink
where ElInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "EL expression uses parameter value $@ without sanitization", source.getNode(), "message term"

/**
 * @name Message interpolation EL injection - trace from annotation message to EL eval
 * @description Traces user-controlled constraint message annotations to EL expression evaluation
 * @kind path-problem
 * @problem.severity error
 * @id java/el-injection-annotation-message
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Track how annotation message values reach the message interpolation
module ELInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: annotation message attribute - returned by getAnnotationAttribute
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getMessage") and
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.validation", "ConstraintViolation")
      ) or (
        // Getting the 'message' from the constraint annotation descriptor
        mc.getMethod().hasName("getMessage") and
        mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.internal.engine", "MessageInterpolatorContext")
      ) or (
        mc.getMethod().hasName("interpolate") and
        mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator") and
        source.asParameter() = mc.getMethod().getParameter(0)
      )
    |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: EL createValueExpression - the string being evaluated as EL
    exists(MethodCall mc |
      mc.getMethod().hasName("createValueExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.el", "ExpressionFactory") and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module ELInjectionFlow = TaintTracking::Global<ELInjectionConfig>;
import ELInjectionFlow::PathGraph

from ELInjectionFlow::PathNode source, ELInjectionFlow::PathNode sink
where ELInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "EL injection: message flows to EL evaluation from $@", source.getNode(), "source"

/**
 * @name Annotation attribute substitution before EL evaluation
 * @description Checks if annotation attribute values are substituted into message string before EL evaluation, enabling injection
 * @kind path-problem
 * @problem.severity error
 * @id java/annotation-attr-to-el-injection
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// The key vulnerability: annotation attribute values are substituted into the message
// via replaceAnnotationAttributes/resolveParameter, then the result is evaluated as EL
// So if an annotation attribute contains "${...}" this gets evaluated
module AnnotationAttrELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: getting annotation attribute values (these can be user-controlled via custom constraints or message templates)
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getAttribute") and
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang.annotation", "Annotation")
      ) or (
        mc.getMethod().hasName("getAttributes") and
        mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.internal.util.annotation", "AnnotationDescriptor")
      ) or (
        mc.getMethod().hasName("getAttribute") and
        mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.internal.util.annotation", "AnnotationDescriptor")
      ) or (
        // resolveParameter returns a string formed from annotation attributes
        mc.getMethod().hasName("resolveParameter") and
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator")
      )
    |
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: the term passed to ElTermResolver.interpolate 
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolate") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.internal.engine.messageinterpolation", "ElTermResolver") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Or directly to createValueExpression
    exists(MethodCall mc |
      mc.getMethod().hasName("createValueExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.el", "ExpressionFactory") and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module AnnotationAttrELFlow = TaintTracking::Global<AnnotationAttrELConfig>;
import AnnotationAttrELFlow::PathGraph

from AnnotationAttrELFlow::PathNode source, AnnotationAttrELFlow::PathNode sink
where AnnotationAttrELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Annotation attribute value flows to EL evaluation from $@", source.getNode(), "annotation attribute"

/**
 * @name Annotation parameter value substituted into EL expression string
 * @description resolveParameter substitutes annotation attribute values into message; if a {param} value contains ${...} this becomes an EL expression
 * @kind path-problem
 * @problem.severity error
 * @id java/annotation-param-el-injection-path
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module ParamELConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // resolveParameter returns annotation attribute value substituted into message string
    exists(MethodCall mc |
      mc.getMethod().hasName("resolveParameter") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator") and
      source.asExpr() = mc
    )
    or
    // interpolateBundleMessage return value — bundle message with param substitution
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolateBundleMessage") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator") and
      source.asExpr() = mc
    )
    or
    // interpolateMessage first arg (the full message string after param resolution)
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolateMessage") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator") and
      source.asExpr() = mc.getArgument(0)
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // interpolateExpression call (which calls ElTermResolver)
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolateExpression") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Direct to ElTermResolver.interpolate
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolate") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.internal.engine.messageinterpolation", "ElTermResolver") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Or directly to createValueExpression
    exists(MethodCall mc |
      mc.getMethod().hasName("createValueExpression") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.el", "ExpressionFactory") and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module ParamELFlow = TaintTracking::Global<ParamELConfig>;
import ParamELFlow::PathGraph

from ParamELFlow::PathNode source, ParamELFlow::PathNode sink
where ParamELFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Annotation attribute value reaches EL evaluation from $@", source.getNode(), "parameter substitution"

/**
 * @name Complete EL injection chain confirmation - resolveMessage result to interpolateExpression
 * @description Confirms the two-phase interpolation: resolveMessage result (with annotation attr substitution)
 *              is directly passed to interpolateExpression for EL evaluation without sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/complete-el-injection-chain
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module CompleteELChainConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: return value of resolveMessage (message string with {param} substitution already done)
    exists(MethodCall mc |
      mc.getMethod().hasName("resolveMessage") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: interpolateExpression call argument (string being EL-evaluated)
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolateExpression") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.messageinterpolation", "AbstractMessageInterpolator") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Or directly to ElTermResolver.interpolate
    exists(MethodCall mc |
      mc.getMethod().hasName("interpolate") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.hibernate.validator.internal.engine.messageinterpolation", "ElTermResolver") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module CompleteELChainFlow = TaintTracking::Global<CompleteELChainConfig>;
import CompleteELChainFlow::PathGraph

from CompleteELChainFlow::PathNode source, CompleteELChainFlow::PathNode sink
where CompleteELChainFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "EL injection: resolveMessage output (with annotation attr values) flows to EL evaluation at $@", source.getNode(), "resolveMessage"
